const purchases = $input.all();

const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA',
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR'
};

const reverseMap = {};
for (const [short, yahoo] of Object.entries(yahooMap)) {
  reverseMap[yahoo] = short;
}

const netQty = {};
const nameMap = {};
for (const item of purchases) {
    const ticker = (item.json.ticker || '').toUpperCase().trim();
    const qty = parseFloat(item.json.quantity) || 0;
    if (!ticker || ticker.startsWith('CASH-')) continue;
    netQty[ticker] = (netQty[ticker] || 0) + qty;
    if (!nameMap[ticker]) nameMap[ticker] = item.json.name || ticker;
}

const tickers = [];
for (const [ticker, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    const yahooTicker = yahooMap[ticker] || ticker;
    if (!reverseMap[yahooTicker]) reverseMap[yahooTicker] = ticker;
    if (!tickers.includes(yahooTicker)) tickers.push(yahooTicker);
}

const batch = tickers.slice(0, 20);
const allTickers = batch.join(',');

return [{ json: { allTickers, reverseMap, nameMap } }];

const reverseMap = $('Build Tickers').first().json.reverseMap;
const sparkData = $input.first().json;
const pricesObj = {};

if (sparkData?.spark?.result) {
    for (const res of sparkData.spark.result) {
        if (!res?.response?.[0]?.meta) continue;
        const yahooTicker = res.symbol;
        const shortTicker = reverseMap[yahooTicker] || yahooTicker;
        const meta = res.response[0].meta;
        const price = meta.regularMarketPrice || 0;
        const previousClose = meta.chartPreviousClose || meta.previousClose || price;
        const currency = meta.currency || 'EUR';
        const dayChangePct = previousClose > 0 ? (price - previousClose) / previousClose * 100 : 0;
        if (price > 0) {
            pricesObj[shortTicker] = { price, currency, dayChangePct };
        }
    }
}

return [{ json: { prices: pricesObj } }];

const currentPrices = $('Parse Prices').first().json.prices;
const nameMap = $('Build Tickers').first().json.nameMap || {};
const prevDoc = $input.first().json || {};

// alertState is stored separately from prices to avoid nesting issues
// Structure: { "TICKER": { ts: timestamp_ms, pct: last_alerted_pct } }
const prevAlertState = prevDoc.alertState || {};

const today = new Date();
today.setHours(0, 0, 0, 0);
const todayTs = today.getTime();
const now = Date.now();
const COOLDOWN_MS = 20 * 60 * 1000;

const alerts = [];
const newAlertState = Object.assign({}, prevAlertState);

for (const [ticker, data] of Object.entries(currentPrices)) {
    const pct = data.dayChangePct || 0;
    const absPct = Math.abs(pct);

    if (absPct < 1.0) continue;

    const prev = prevAlertState[ticker] || {};
    const lastTs = typeof prev.ts === 'number' ? prev.ts : 0;
    const lastPct = typeof prev.pct === 'number' ? prev.pct : 0;

    const alertedToday = lastTs >= todayTs;
    const movedEnough = !alertedToday || absPct >= Math.abs(lastPct) + 1.0;
    const cooledDown = (now - lastTs) >= COOLDOWN_MS;

    if (movedEnough && (!alertedToday || cooledDown)) {
        const name = nameMap[ticker] || ticker;
        alerts.push({ ticker, name, pct, price: data.price, currency: data.currency || 'EUR' });
        newAlertState[ticker] = { ts: now, pct: pct };
    }
}

// Sort by ascending pct value (most negative first, most positive last)
alerts.sort(function(a, b) { return a.pct - b.pct; });

return [{ json: {
    hasAlerts: alerts.length > 0,
    alerts,
    currentPrices,
    newAlertState
}}];

const { alerts } = $input.first().json;

const NL = '\n';
const lines = alerts.map(function(a) {
    const emoji = a.pct >= 0 ? '&#128994;' : '&#128308;';
    const sign = a.pct >= 0 ? '+' : '';
    const label = a.name || a.ticker;
    return emoji + ' <b>' + label + '</b> : ' + sign + a.pct.toFixed(2) + '% aujourd\'hui (' + a.price.toFixed(2) + ' ' + a.currency + ')';
}).join(NL);

const message = '&#128202; <b>Alerte Variation Journaliere</b>' + NL + NL + lines + NL + NL + '<i>Seuil : &#177;1% / jour. Prochaine alerte si +1% suppl.</i>';

return [{ json: { chatId: '2089017736', message } }];
